    97→  @Test
    98→  void testObjectMinCardinality() {
    99→    // TestClass subClassOf (hasProperty min 1 TargetClass)
   100→    var restriction = factory.getOWLObjectMinCardinality(1, hasProperty, targetClass);
   101→    var axiom = factory.getOWLSubClassOfAxiom(testClass, restriction);
   102→    manager.addAxiom(ontology, axiom);
   103→
   104→    SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing);
   105→    testClass.accept(visitor);
   106→
   107→    Map<String, Set<RestrictionInfo>> restrictions = visitor.getRestrictions();
   108→    assertTrue(restrictions.containsKey("hasProperty"));
   109→
   110→    Set<RestrictionInfo> infos = restrictions.get("hasProperty");
   111→    assertEquals(1, infos.size());
   112→    assertInstanceOf(RestrictionInfo.MinCardinality.class, infos.stream().findFirst().orElseThrow(),
   113→        "Should be MinCardinality restriction");
   114→
   115→    RestrictionInfo.MinCardinality minCard = (RestrictionInfo.MinCardinality) infos.stream()
   116→        .findFirst().orElseThrow();
   117→    assertEquals(1, minCard.cardinality().orElse(-1), "Cardinality should be 1");
   118→    assertTrue(minCard.impliesRequired(), "Min cardinality 1 implies required");
   119→  }
